export type ParsedSwapTokensInstruction<
  TProgram extends string = typeof AMMS_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    trader: TAccountMetas[0];
    mintA: TAccountMetas[1];
    traderAccountA: TAccountMetas[2];
    mintB: TAccountMetas[3];
    traderAccountB: TAccountMetas[4];
    poolInfo: TAccountMetas[5];
    poolAuthority: TAccountMetas[6];
    reserveA: TAccountMetas[7];
    reserveB: TAccountMetas[8];
    associatedTokenProgram: TAccountMetas[9];
    tokenProgram: TAccountMetas[10];
  };
  data: SwapTokensInstructionData;
};

export function parseSwapTokensInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedSwapTokensInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 11) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 11,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      trader: getNextAccount(),
      mintA: getNextAccount(),
      traderAccountA: getNextAccount(),
      mintB: getNextAccount(),
      traderAccountB: getNextAccount(),
      poolInfo: getNextAccount(),
      poolAuthority: getNextAccount(),
      reserveA: getNextAccount(),
      reserveB: getNextAccount(),
      associatedTokenProgram: getNextAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getSwapTokensInstructionDataDecoder().decode(instruction.data),
  };
}
